// Kandidaten fuer die Agenten-Kette (Eignung/Fakten/QA/Lern/Satire):
// Analyse muss abgeschlossen sein (lastAnalysisAt gesetzt) und die Kette darf fuer diese
// Zeile noch nicht gelaufen sein (judgmentChainProcessedAt leer). Bewusst kein contentStage-Filter:
// die Kette lief im urspruenglichen P3 unconditional fuer jede analysierte Zeile, unabhaengig vom
// abgeleiteten contentStage (watching/ignored/needs_content).
const items = $input.all();
function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
return items.filter(item => {
  const j = item.json || {};
  return !!safeStr(j.lastAnalysisAt) && !safeStr(j.judgmentChainProcessedAt);
});

// Sortierung: 1. firstseen aufsteigend, 2. volfdnr numerisch, 3. vorgangKey lexikografisch
function parseDate(v) {
  if (!v) return 0;
  const t = Date.parse(String(v));
  return Number.isFinite(t) ? t : 0;
}
function parseVolfdnr(v) {
  if (!v) return Infinity;
  const n = parseInt(String(v).replace(/[^0-9]/g, ''), 10);
  return Number.isFinite(n) ? n : Infinity;
}
const items = $input.all();
items.sort((a, b) => {
  const ja = a.json || {}, jb = b.json || {};
  const fa = parseDate(ja.firstseen), fb = parseDate(jb.firstseen);
  if (fa !== fb) return fa - fb;
  const va = parseVolfdnr(ja.volfdnr), vb = parseVolfdnr(jb.volfdnr);
  if (va !== vb) return va - vb;
  return String(ja.vorgangKey || '').localeCompare(String(jb.vorgangKey || ''));
});
return items;

function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function parseObj(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  try { const p = JSON.parse(String(v)); return (p && typeof p === 'object' && !Array.isArray(p)) ? p : {}; }
  catch (e) { return {}; }
}

const row = $json;
const analysis = parseObj(row.analysisJson);
const sl = parseObj(analysis.sourceLock);
const va = parseObj(analysis.visualAnchors);
const guardErrors = Array.isArray(analysis.visualGuardErrors) ? analysis.visualGuardErrors : [];

return {
  json: {
    vorgangKey: safeStr(row.vorgangKey),
    vorgangsnummer: safeStr(row.vorgangsnummer),
    title: safeStr(row.title),

    relevanz: analysis.relevanz,
    sprengstoff: row.sprengstoff,
    empfehlung: row.empfehlung,
    kommunikationspotenzial: row.kommunikationspotenzial,
    oeffentlicheGelderBetroffen: analysis.oeffentlicheGelderBetroffen === true,

    sourceLock: sl,
    visualAnchors: va,

    kurzfassung: row.kurzfassung,
    warumRelevant: row.warumRelevant,

    sourceLockValid: analysis.sourceLockValid === true,
    visualAnchorsValid: analysis.visualAnchorsValid === true,
    guardValid: guardErrors.length === 0,
    visualGuardErrors: guardErrors
  }
};

function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }

const response = $json || {};
const original = $('Eignungs-Agent: Baue Eingabe').itemMatching($itemIndex).json || {};
const hasResult = typeof response.satireWorthIt === 'boolean';

const eignung = hasResult ? response : {
  vorgangKey: safeStr(original.vorgangKey),
  vorgangsnummer: safeStr(original.vorgangsnummer),
  satireWorthIt: false,
  satireWorthItReason: 'Eignungs-Agent Aufruf fehlgeschlagen - sicherheitshalber kein Sharepic',
  reservations: [],
  reservationsBlockImage: false,
  parseError: true,
  callFailed: true
};

return { json: { ...original, eignungsAgentJson: JSON.stringify(eignung), _eignung: eignung } };

function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function asArr(v) { return Array.isArray(v) ? v.filter(Boolean).map(safeStr) : []; }

const j = $json;
const original = $('Eignungs-Agent: Baue Eingabe').itemMatching($itemIndex).json || {};
const row = $('Loop Vorgaenge').itemMatching($itemIndex).json || {};

const eignung = j._eignung || {};
const satireWorthIt = eignung.satireWorthIt === true;
const sourceLockValid = original.sourceLockValid === true;
const visualAnchorsValid = original.visualAnchorsValid === true;
const guardValid = original.guardValid === true;
const reservationsBlockImage = eignung.reservationsBlockImage === true;

const sharepicRecommended = satireWorthIt && sourceLockValid && visualAnchorsValid && guardValid && !reservationsBlockImage;

let sharepicNeedStage;
let sharepicNeedReason;

if (!satireWorthIt) {
  sharepicNeedStage = 'not_applicable';
  sharepicNeedReason = 'Eignungs-Agent: ' + (safeStr(eignung.satireWorthItReason) || 'Kein Sharepic-Bedarf');
} else if (sharepicRecommended) {
  sharepicNeedStage = 'topic_ok';
  sharepicNeedReason = 'Sharepic freigegeben: Eignungs-Agent + SourceLock/Visual-Anker/Guard bestanden.';
} else {
  sharepicNeedStage = 'topic_error';
  const reasons = [];
  if (!sourceLockValid) reasons.push('sourceLock unvollstaendig');
  if (!visualAnchorsValid) reasons.push('visualAnchors unvollstaendig');
  if (!guardValid) reasons.push('Guard blockiert: ' + asArr(original.visualGuardErrors).join(' | '));
  if (reservationsBlockImage) reasons.push('Eignungs-Agent Bedenken: ' + asArr(eignung.reservations).join(' | '));
  sharepicNeedReason = 'Sharepic blockiert: ' + reasons.join(' | ');
}

return {
  json: {
    ...row,
    eignungsAgentJson: j.eignungsAgentJson,
    sharepicNeedStage: sharepicNeedStage,
    visualDecisionReason: sharepicNeedReason,
    instagramSharepicNoetig: sharepicNeedStage === 'topic_ok',
    instagramCarouselNoetig: sharepicNeedStage === 'topic_ok',
    visualNeeded: sharepicNeedStage === 'topic_ok',
    contentStage: sharepicNeedStage === 'topic_ok' ? 'awaiting_kernbotschaft' : safeStr(row.contentStage)
  }
};

function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function parseObj(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  try { const p = JSON.parse(String(v)); return (p && typeof p === 'object' && !Array.isArray(p)) ? p : {}; }
  catch (e) { return {}; }
}
function asArray(v) { return Array.isArray(v) ? v.filter(Boolean).map(safeStr) : []; }

const analysis = parseObj($json.analysisJson);
const sourceLock = parseObj(analysis.sourceLock);

return {
  json: {
    vorgangKey: $json.vorgangKey,
    vorgangsnummer: $json.vorgangsnummer,
    title: $json.title,
    summaryText: $json.summaryText,
    combinedText: $json.combinedText,
    sprengstoff: safeStr(analysis.sprengstoff) || 'GERING',
    oldSourceTopic: safeStr(sourceLock.sourceTopic),
    oldRequiredTerms: asArray(sourceLock.requiredTerms),
    oldRequiredObjects: asArray(sourceLock.requiredObjects)
  }
};

function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function asArray(v) { return Array.isArray(v) ? v.filter(Boolean).map(safeStr) : []; }

const response = $json || {};
const original = $('Fakten-Shadow: Baue Eingabe').itemMatching($itemIndex).json || {};
const hasFakten = typeof response.sourceTopic === 'string';

const fakten = hasFakten ? response : {
  vorgangKey: safeStr(original.vorgangKey),
  vorgangsnummer: safeStr(original.vorgangsnummer),
  sourceTopic: '', sourceConflict: '', requiredTerms: [], requiredObjects: [],
  requiredAction: '', affectedGroups: [], concreteNumbers: [], responsibilities: [],
  documentType: '', quotesVerbatim: [],
  parseError: true,
  callFailed: true
};

// Vergleich gegen das bereits VOR der Sub-Workflow-Grenze extrahierte sourceLock (siehe Fakten-Shadow: Baue Eingabe) - kein KI-Urteil.
const oldSourceLock = {
  sourceTopic: safeStr(original.oldSourceTopic),
  requiredTerms: asArray(original.oldRequiredTerms),
  requiredObjects: asArray(original.oldRequiredObjects)
};

function normalizeText(v) {
  return safeStr(v).toLowerCase()
    .replace(/ä/g, 'ae').replace(/ö/g, 'oe').replace(/ü/g, 'ue').replace(/ß/g, 'ss');
}
function stemLight(w) {
  return w.replace(/(ungen|ierung|heit|keit|schaft|tion|ieren|iere|iert|ung|lich|isch|ische|ischen|ischer|isches)$/, '').replace(/(en|er|em|es|e|n|s|t)$/, '');
}
function tokenOverlap(a, b) {
  const tokensA = normalizeText(a).split(/[\W_]+/).filter(w => w.length >= 4).map(stemLight);
  const tokensB = normalizeText(b).split(/[\W_]+/).filter(w => w.length >= 4).map(stemLight);
  if (tokensA.some(w => tokensB.includes(w))) return true;
  const rawA = normalizeText(a).replace(/[\W_]+/g, ''), rawB = normalizeText(b).replace(/[\W_]+/g, '');
  for (const tok of tokensA) { if (tok.length >= 5 && rawB.includes(tok)) return true; }
  for (const tok of tokensB) { if (tok.length >= 5 && rawA.includes(tok)) return true; }
  return false;
}

const oldRequiredTerms = asArray(oldSourceLock.requiredTerms);
const newRequiredTerms = asArray(fakten.requiredTerms);
const oldRequiredObjects = asArray(oldSourceLock.requiredObjects);
const newRequiredObjects = asArray(fakten.requiredObjects);

const termsMatched = newRequiredTerms.filter(t => oldRequiredTerms.some(o => tokenOverlap(t, o))).length;
const objectsMatched = newRequiredObjects.filter(t => oldRequiredObjects.some(o => tokenOverlap(t, o))).length;
const sourceTopicOverlap = (safeStr(oldSourceLock.sourceTopic) && safeStr(fakten.sourceTopic))
  ? tokenOverlap(oldSourceLock.sourceTopic, fakten.sourceTopic)
  : false;

const comparison = {
  sourceTopicOverlap: sourceTopicOverlap,
  requiredTermsMatched: termsMatched,
  requiredTermsOldCount: oldRequiredTerms.length,
  requiredTermsNewCount: newRequiredTerms.length,
  requiredObjectsMatched: objectsMatched,
  requiredObjectsOldCount: oldRequiredObjects.length,
  requiredObjectsNewCount: newRequiredObjects.length
};

return {
  json: {
    vorgangKey: safeStr(original.vorgangKey),
    sprengstoff: safeStr(original.sprengstoff) || 'GERING',
    faktenAgentJson: JSON.stringify(fakten),
    faktenComparisonJson: JSON.stringify(comparison)
  }
};

// Cutover 2026-07-18: laeuft nach Fakten+Satire-Gate (nicht mehr parallel zu Fakten),
// prueft echten Fakten-Agent-SourceLock statt P3s alter Extraktion.
// P3d-Port 2026-07-19: analysisJson jetzt direkt aus der DB-Zeile (Parse Analyse JSON existiert
// hier nicht) - Speichere Analyse hat den gleichen Wert bereits geschrieben, bevor P3d laeuft.
// FIX: sourceConflict nicht mehr als Pflichtfeld gewertet (optional laut Fakten-Agent-Spec,
// gleicher Bug wie im QA-Agent selbst, dort am 2026-07-19 behoben).
function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function parseObj(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  try { const p = JSON.parse(String(v)); return p && typeof p === 'object' && !Array.isArray(p) ? p : {}; }
  catch (e) { return {}; }
}
function asArr(v) {
  if (Array.isArray(v)) return v.filter(Boolean).map(safeStr);
  if (typeof v === 'string' && v.trim()) { try { const p = JSON.parse(v); if (Array.isArray(p)) return p.filter(Boolean).map(safeStr); } catch (e) {} }
  return [];
}

const base = $('Fakten-Shadow: Baue Eingabe').item.json || {};
const row = $('Loop Vorgaenge').itemMatching($itemIndex).json || {};
const analysis = parseObj(row.analysisJson);
const fakten = parseObj($('Stelle Kontext nach Fakten-Agent wieder her').item.json.faktenAgentJson);

const sourceLock = {
  sourceTopic: safeStr(fakten.sourceTopic),
  sourceConflict: safeStr(fakten.sourceConflict),
  requiredTerms: asArr(fakten.requiredTerms),
  requiredObjects: asArr(fakten.requiredObjects),
  requiredAction: safeStr(fakten.requiredAction)
};
const sourceLockValid = !!(sourceLock.sourceTopic && sourceLock.requiredTerms.length >= 2 && fakten.parseError !== true);
const mergedAnalysisJson = JSON.stringify({ ...analysis, sourceLock, sourceLockValid });

return {
  json: {
    qaStage: 'analyse',
    vorgangKey: safeStr(base.vorgangKey),
    vorgangsnummer: safeStr(base.vorgangsnummer),
    title: safeStr(base.title),
    analysisJson: mergedAnalysisJson,
    summaryText: safeStr(base.summaryText),
    combinedText: safeStr(base.combinedText),
    skipAdversarialCheck: false
  }
};

function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }

const response = $json || {};
const original = $('QA-Shadow: Baue QA-Eingabe').item.json || {};
const hasVerdict = typeof response.passed === 'boolean';

const verdict = hasVerdict ? response : {
  passed: false,
  violations: [{ code: 'qa_agent_call_failed', field: 'qaVerdictJson', message: 'QA-Agent-Aufruf fehlgeschlagen oder ohne Verdikt zurueckgekehrt', severity: 'unknown' }],
  hallucinationSuspects: [],
  sourceLockBreaches: [],
  qaStage: 'analyse',
  vorgangKey: safeStr(original.vorgangKey),
  vorgangsnummer: safeStr(original.vorgangsnummer),
  checkedAt: new Date().toISOString(),
  aiSkipped: true
};

return {
  json: {
    ...original,
    qaVerdictJson: JSON.stringify(verdict),
    qaPassed: verdict.passed === true,
    qaCheckedAt: verdict.checkedAt || new Date().toISOString()
  }
};

function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function asArr(v) { return Array.isArray(v) ? v : []; }

const j = $json;
const violations = asArr(j.violations).map(v => safeStr(v && v.message)).filter(Boolean);
const hallucinations = asArr(j.hallucinationSuspects).map(h => safeStr(h && h.claim)).filter(Boolean);
const reasons = [...violations, ...hallucinations];

const lines = [
  '⚠️ QA-Block: Vorgang ' + safeStr(j.vorgangsnummer) + ' (' + safeStr(j.vorgangKey) + ')',
  reasons.length ? 'Grund: ' + reasons.join(' | ') : 'Grund: unbekannt (QA-Agent-Aufruf evtl. fehlgeschlagen)',
  'Bitte in der Data Table pruefen und contentStage/sharepicNeedStage nach Korrektur manuell zuruecksetzen.'
];

return {
  json: {
    ...j,
    txnId: 'qa-block-' + Date.now() + '-' + Math.random().toString(36).slice(2),
    summaryMessage: lines.join('\n')
  }
};

function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function parseObj(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  try { const p = JSON.parse(String(v)); return (p && typeof p === 'object' && !Array.isArray(p)) ? p : {}; }
  catch (e) { return {}; }
}

const row = $json;
const verdict = parseObj(row.qaVerdictJson);
const outcome = row.qaPassed === true ? 'accepted' : 'rejected';

const violations = Array.isArray(verdict.violations) ? verdict.violations : [];
const hallucinations = Array.isArray(verdict.hallucinationSuspects) ? verdict.hallucinationSuspects : [];

let exampleSummary;
if (outcome === 'accepted') {
  exampleSummary = safeStr(row.title) + ' - QA bestanden, keine Verstoesse.';
} else {
  const firstIssues = [...violations.map(v => v.message), ...hallucinations.map(h => h.claim)].filter(Boolean).slice(0, 3);
  exampleSummary = safeStr(row.title) + ' - ' + (firstIssues.length ? firstIssues.join(' | ') : 'QA abgelehnt ohne Detail');
}

return {
  json: {
    lernAction: 'record',
    vorgangKey: safeStr(row.vorgangKey),
    vorgangsnummer: safeStr(row.vorgangsnummer),
    qaStage: safeStr(row.qaStage) || 'analyse',
    source: 'qa_agent',
    outcome: outcome,
    exampleSummary: exampleSummary.slice(0, 500),
    detailsJson: safeStr(row.qaVerdictJson) || '{}'
  }
};

// Nächster Repair-Vorgang (V12_7)
const items = $input.all();
const rawItem = items && items[0];
const j = (rawItem && rawItem.json && typeof rawItem.json === 'object' && !Array.isArray(rawItem.json))
  ? rawItem.json
  : {};
return [{ json: j }];

const now = Date.now();
const owner = `ALLRIS_P3d_Agenten_Kette:${$execution.id}`;
return items
  .filter(item => {
    const j = item.json || {};
    const oldOwner = String(j.claim_owner || '').trim();
    const expires = Date.parse(String(j.claim_expires_at || ''));
    return !oldOwner || !Number.isFinite(expires) || expires <= now;
  })
  .map(item => ({ json: {
    ...item.json,
    claimAction: 'acquire',
    claimOwner: owner,
    claimStage: 'judgment',
    leaseMinutes: 30,
    expectedClaimOwner: item.json.claim_owner ?? null,
    expectedClaimExpiresAt: item.json.claim_expires_at ?? null
  } }));

const vorgangKey = String($json.vorgangKey || '').trim();
if (!vorgangKey) throw new Error('[P3d Claim Release] vorgangKey fehlt.');
return [{ json: { vorgangKey, claimAction: 'release', claimOwner: `ALLRIS_P3d_Agenten_Kette:${$execution.id}` } }];
